  /// Returns pre-written content for the given sign and date, or null if not available.
  /// Only returns a bundle when today, yesterday, and tomorrow are all present.
  static Map<String, String>? getBundle(String sign, DateTime date) {
    final key = _dateKey(date);
    final dayContent = _content[key]?[sign];
    if (dayContent == null) return null;

    final yesterday = date.subtract(const Duration(days: 1));
    final tomorrow = date.add(const Duration(days: 1));
    final yesterdayContent = _content[_dateKey(yesterday)]?[sign];
    final tomorrowContent = _content[_dateKey(tomorrow)]?[sign];

    if (yesterdayContent == null || tomorrowContent == null) return null;

    return {
      'yesterday': yesterdayContent.general,
      'yesterday_mood': yesterdayContent.mood,
      'yesterday_career': yesterdayContent.career,
      'yesterday_love': yesterdayContent.love,
      'today': dayContent.general,
      'today_mood': dayContent.mood,
      'today_career': dayContent.career,
      'today_love': dayContent.love,
      'tomorrow': tomorrowContent.general,
      'tomorrow_mood': tomorrowContent.mood,
      'tomorrow_career': tomorrowContent.career,
      'tomorrow_love': tomorrowContent.love,
    };
  }

  static String _dateKey(DateTime date) {
    return '${date.year}-${date.month.toString().padLeft(2, '0')}'
        '-${date.day.toString().padLeft(2, '0')}';
  }

  /// Builds a day map with Mongolian content. Each string = general for one sign (Aries..Pisces).
  static Map<String, _DayContent> _mongolianDay(
    String aries,
    String taurus,
    String gemini,
    String cancer,
    String leo,
    String virgo,
    String libra,
    String scorpio,
    String sagittarius,
    String capricorn,
    String aquarius,
    String pisces,
  ) {
    const mood =
        'Сэтгэл хөдлөлөө тодруулахад тохиромжтой өдөр. Өөрийн дотоод дуу хоолойгоо сонс.';
    const career =
        'Ажил мэргэжилд анхаарлаа төвлөрүүл. Нэг чухал ажлыг дуусгахад тохиромжтой өдөр.';
    const love =
        'Хайр дурлалд шударга, нээлттэй бай. Холбоо бэхжих боломжтой өдөр.';
    return {
      'Aries': _DayContent(general: aries, mood: mood, career: career, love: love),
      'Taurus': _DayContent(general: taurus, mood: mood, career: career, love: love),
      'Gemini': _DayContent(general: gemini, mood: mood, career: career, love: love),
      'Cancer': _DayContent(general: cancer, mood: mood, career: career, love: love),
      'Leo': _DayContent(general: leo, mood: mood, career: career, love: love),
      'Virgo': _DayContent(general: virgo, mood: mood, career: career, love: love),
      'Libra': _DayContent(general: libra, mood: mood, career: career, love: love),
      'Scorpio': _DayContent(general: scorpio, mood: mood, career: career, love: love),
      'Sagittarius': _DayContent(general: sagittarius, mood: mood, career: career, love: love),
      'Capricorn': _DayContent(general: capricorn, mood: mood, career: career, love: love),
      'Aquarius': _DayContent(general: aquarius, mood: mood, career: career, love: love),
      'Pisces': _DayContent(general: pisces, mood: mood, career: career, love: love),
    };
  }
}

class _DayContent {
  final String general;
  final String mood;
  final String career;
  final String love;

  const _DayContent({
    required this.general,
    required this.mood,
    required this.career,
    required this.love,
  });
}